# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import secrets
import sqlite3
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

def get_db():
    conn = sqlite3.connect('users.db')
    conn.row_factory = sqlite3.Row
    return conn

def send_reset_email(email, token):
    # Simplified email sending - replace with your email service
    reset_link = f"http://yoursite.com/reset?token={token}"
    # In production, use proper email service like SendGrid or SMTP
    print(f"Reset link sent to {email}: {reset_link}")

@app.route('/reset_request', methods=['POST'])
def reset_request():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email required'}), 400
    
    conn = get_db()
    user = conn.execute('SELECT * FROM users WHERE email = ?', (email,)).fetchone()
    
    if not user:
        return jsonify({'message': 'If email exists, reset link sent'}), 200
    
    token = secrets.token_urlsafe(32)
    conn.execute('INSERT INTO password_resets (email, token) VALUES (?, ?)', (email, token))
    conn.commit()
    
    send_reset_email(email, token)
    
    return jsonify({'message': 'Reset link sent if email exists'}), 200

@app.route('/reset', methods=['POST'])
def reset_password():
    data = request.get_json()
    token = data.get('token')
    new_password = data.get('password')
    
    if not token or not new_password:
        return jsonify({'error': 'Token and password required'}), 400
    
    conn = get_db()
    reset_record = conn.execute('SELECT * FROM password_resets WHERE token = ?', (token,)).fetchone()
    
    if not reset_record:
        return jsonify({'error': 'Invalid token'}), 400
    
    # Update user password (simplified)
    conn.execute('UPDATE users SET password = ? WHERE email = ?', (new_password, reset_record['email']))
    conn.execute('DELETE FROM password_resets WHERE token = ?', (token,))
    conn.commit()
    
    return jsonify({'message': 'Password reset successfully'}), 200

if __name__ == '__main__':
    conn = get_db()
    conn.execute('''CREATE TABLE IF NOT EXISTS users
                   (id INTEGER PRIMARY KEY, email TEXT UNIQUE, password TEXT)''')
    conn.execute('''CREATE TABLE IF NOT EXISTS password_resets
                   (id INTEGER PRIMARY KEY, email TEXT, token TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)''')
    conn.commit()
    conn.close()
    app.run(debug=True)